    def get_send_lock(self, player_id: str) -> asyncio.Lock:
        lock = self._send_locks.get(player_id)
        if lock is None:
            lock = asyncio.Lock()
            self._send_locks[player_id] = lock
        return lock

    def ensure_player(self, player_id: str, name: Optional[str] = None) -> Player:
        p = self.players.get(player_id)
